VALUES
  ('aboriginal-8b44517b-moex-00032', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '依照原住民身分法規定，原住民與非原住民結婚所生子女，從具原住民身分之父或母之姓或原住民傳 統名字者，取得原住民身分。若得依此規定申請改姓或取用原住民族傳統名字取得原住民身分者，但 於中華民國109年12月31日前死亡，因此未取得原住民身分，其子女於什麼時間前，準用此規定， 取得原住民身分？', '["中華民國110年12月31日", "中華民國111年01月01日", "中華民國111年12月31日", "中華民國112年01月01日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00033', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '下列有關於地方制度法之規範的敘述，何者為誤？', '["直轄市之區由山地鄉改制者，稱直轄市山地原住民區", "山地原住民區之自治，除法律另有規定外，準用地方制度法關於鄉（鎮、市）之規定", "山地原住民區實施自治所需財源，由直轄市依山地原住民區之自治事項、直轄市改制前各該山地鄉 前三年度稅課收入平均數等因素，予以設算補助，並維持改制前各該山地鄉統籌分配財源水準", "山地原住民區自治事項，包含山地原住民區殯葬設施之設置及管理、山地原住民區道路之建設及管 理、山地原住民區公共造產事業之經營及管理、山地原住民區內國土功能分區之劃設及土地使用管 制之執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00034', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '下列有關於原住民族基本法以及諮商取得原住民族部落同意參與辦法之規範的敘述，何者正確？', '["原住民族基本法第21條所稱原住民族或部落同意，指過三分之二以上關係部落，依諮商取得原住 民族部落同意參與辦法召開部落會議議決通過", "關係部落由同意事項所在地之鄉（鎮、市、區）公所依前項規定認定之；認定有困難時，應敘明爭 議事項及處理意見，報請所在地之直轄市、縣（市）原住民族主管機關認定", "關係部落之部落會議主席自收受同意事項之通知，逾2個月未召集部落會議時，申請人得申請關係 部落所在地之鄉（鎮、市、區）公所代行召集", "部落會議議決同意事項，以部落全體原住民家戶代表過半數出席，出席原住民家戶代表三分之二以 上贊成，為通過"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00035', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '以下有關於司法院釋字第803號解釋中，針對原住民族基於傳統文化及祭儀需要獵捕宰殺利用野生動 物管理辦法第4條之解釋的敘述，何者為誤？', '["該條文第3項有關非定期性獵捕活動所定之申請期限與程序規定部分，其中就突發性未可事先預期 者，欠缺合理彈性，對原住民從事狩獵活動之文化權利所為限制已屬過度，於此範圍內，有違憲法 比例原則", "該條文第4項第4款規定，前項申請書應載明獵捕動物之種類、數量之部分，違反憲法比例原則", "有關於非定期性獵捕活動所定之申請期限與程序，以及申請書應載明獵捕動物之種類、數量等規定， 自本解釋公布之日起不再適用", "有關機關應至遲自本解釋公布之日起 3 年內，依本解釋意旨儘速檢討修正，就上開規範不足之部 分，訂定符合憲法比例原則之規範"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00036', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '根據原住民族教育法施行細則，原住民重點學校，由高級中等以下學校各該教育主管機關認定之，以 下所述之認定規定，何者正確？', '["在原住民族地區，該校原住民學生人數達學生總數三分之一以上者；在非原住民族地區，該校原住 民學生人數達100人以上或達學生總數三分之一以上者", "在原住民族地區，該校原住民學生人數達學生總數二分之一以上者；在非原住民族地區，該校原住 民學生人數達100人以上或達學生總數二分之一以上者", "在原住民族地區，該校原住民學生人數達學生總數三分之一以上者；在非原住民族地區，該校原住 民學生人數達200人以上或達學生總數三分之一以上者", "在原住民族地區，該校原住民學生人數達學生總數二分之一以上者；在非原住民族地區，該校原住 民學生人數達200人以上或達學生總數三分之一以上者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00037', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '以下所述原住民族傳統智慧創作保護條例之規範，何者為誤？', '["智慧創作申請人以原住民族或部落為限", "智慧創作專用權，應永久保護之。智慧創作專用權人消失者，其專用權之保護，視同存續；其專用 權歸屬於全中央原住民族主管機關所有", "智慧創作專用權人享有的智慧創作人格權，包括專有禁止他人以歪曲、割裂、竄改或其他方法改變 其智慧創作之內容、形式或名目致損害其名譽之創作人格權等", "為報導、評論、教育或研究之必要使用者，得使用已公開發表之智慧創作。其使用應註明其出處， 但依使用之目的及方法，於智慧創作專用權人之利益無損害之虞，且不違反社會使用慣例者，不在 此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00038', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '以下有關於原住民族工作權保障法所規範事項之敘述，何者為正確？', '["各級政府機關、公立學校及公營事業機構，除位於澎湖、金門、連江縣外，其僱用約僱人員之總額， 每滿200人應有原住民1人。原住民地區之各級政府機關、公立學校及公營事業機構，其僱用約僱 人員之總額，應有三分之一以上為原住民", "各級政府機關、公立學校及公營事業機構，除位於澎湖、金門、連江縣外，其僱用約僱人員之總額， 每滿100人應有原住民1人。原住民地區之各級政府機關、公立學校及公營事業機構，其僱用約僱 人員之總額，應有二分之一以上為原住民", "各級政府機關、公立學校及公營事業機構，除位於澎湖、金門、連江縣外，其僱用約僱人員之總額， 每滿100人應有原住民1人。原住民地區之各級政府機關、公立學校及公營事業機構，其僱用約僱 人員之總額，應有三分之一以上為原住民", "各級政府機關、公立學校及公營事業機構，除位於澎湖、金門、連江縣外，其僱用約僱人員之總額， 每滿200人應有原住民1人。原住民地區之各級政府機關、公立學校及公營事業機構，其僱用約僱 人員之總額，應有二分之一以上為原住民"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00039', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '下列關於原住民族基本法之規定的敘述，何者錯誤？', '["政府為辦理原住民族土地之調查及處理，應設置原住民族土地調查及處理委員會；其組織及相關事 務，另以法律定之", "原住民族或原住民所有、使用之土地、海域，其回復、取得、處分、計畫、管理及利用等事項，另 以法律定之", "政府應依原住民族意願，保障原住民族之平等地位及自主發展，實行原住民族自治；其相關事項， 另以法律定之", "主管機關應於本法施行後30年內，依本法之原則修正、制定或廢止相關法令"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00040', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '根據山坡地保育利用條例第37條，原住民取得原住民保留地所有權，如有移轉，以原住民為限，但 有特定情形者，得由政府承受私有原住民保留地，以下何者不屬於得由政府承受私有原住民保留地之 特定情形？', '["興辦土地徵收條例第3條、第4條第1項規定之各款事業及所有權人依該條例第8條規定申請一併 徵收", "經中央原住民族主管機關審認符合災害之預防、災害發生時之應變及災後之復原重建用地需求", "稅捐稽徵機關受理以原住民保留地抵繳增值稅", "因公法金錢給付義務之執行事件未能拍定原住民保留地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00041', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '原住民保留地開發管理辦法第27條中規定，第23條至第25條之原住民保留地承租人有特定情形者， 應終止租約收回土地，其所投資之各項設施不予補償。以下所述何者不屬這些特定情形？', '["經原住民保留地土地權利審查委員會提案並通過終止租約者", "違反計畫使用者", "轉租或由他人頂替者", "未依開發或興辦計畫開發或興辦，且未報經核准變更計畫或展延開發、興辦期限者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL)
